external_knowledge:
- "star claimant" metaphorically refers to the policyholder with the most claims;
- "raised the most red flags" is a metaphorical expression meaning to file the highest number of claims;
- "shouting the loudest in the storm of claims" symbolizes being the most active in filing claims amidst many others.

sql:
SELECT name 
FROM policyholders 
WHERE policyholder_id IN (
  SELECT policyholder_id 
  FROM claims
);

SELECT policy_name, AVG(base_premium) AS average_premium
FROM policy_types
GROUP BY policy_name;

SELECT rider_name, SUM(additional_premium) AS total_premium
FROM policy_riders
GROUP BY rider_name;

SELECT gender, COUNT(*) AS frequency
FROM policyholders
GROUP BY gender;

SELECT policy_name, SUM(base_premium) AS total_premium
FROM policy_types
GROUP BY policy_name;

SELECT age_range, ndx 
FROM mortality_tables 
WHERE age_range = '0-1';

SELECT age_range, mortality_rate_type, AVG(nqx) AS average_mortality_rate
FROM mortality_tables
GROUP BY age_range, mortality_rate_type;

SELECT certification, AVG(experience) AS average_experience
FROM actuaries
GROUP BY certification;

SELECT * 
FROM policyholders
WHERE policyholder_id = 5;
